/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications via email.
 * Designed to be extensible for additional channels in the future.
 */

import type { NotificationType } from './notification.js';

/**
 * Email notification frequency — controls batching/delivery cadence.
 * - 'instant': Send immediately when the event occurs.
 * - 'daily':   Batch and send once per day.
 * - 'weekly':  Batch and send once per week.
 */
export type EmailFrequency = 'instant' | 'daily' | 'weekly';

/**
 * Email-specific notification settings.
 */
export interface EmailPreferences {
  /** Whether email notifications are enabled at all. */
  enabled: boolean;
  /** Delivery frequency for email notifications. */
  frequency: EmailFrequency;
  /** Notification types the user is subscribed to. Empty means none. */
  subscribedCategories: NotificationType[];
}

/**
 * A persisted user notification preferences record.
 */
export interface UserPreferences {
  /** Matches the user's ID (one preferences record per user). */
  id: string;
  /** The user this preferences record belongs to. */
  userId: string;
  /** Email notification settings. */
  email: EmailPreferences;
  /** When preferences were created. */
  createdAt: Date;
  /** When preferences were last updated. */
  updatedAt: Date;
}

/**
 * Input for updating email preferences. All fields optional — only
 * specified fields are changed.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * Default email preferences for new users.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailPreferences = {
  enabled: true,
  frequency: 'instant',
  subscribedCategories: [
    'order_confirmation',
    'order_status_update',
    'user_welcome',
    'user_update',
  ],
};

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 * Each user has at most one preferences record (keyed by userId).
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { EmailFrequency } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailFrequency,
        subscribedCategories: JSON.parse(
          record['emailSubscribedCategories'] as string,
        ) as NotificationType[],
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailSubscribedCategories: JSON.stringify(
        entity.email.subscribedCategories,
      ),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — business logic for user notification preferences.
 *
 * Manages CRUD operations on user notification preferences and provides
 * a method for the NotificationService to check whether a notification
 * should be delivered to a given user.
 *
 * Depends on:
 * - PreferencesRepository (data layer) for persistence
 */

import type { NotificationType } from '../models/notification.js';
import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
} from '../models/user-preferences.js';
import { DEFAULT_EMAIL_PREFERENCES } from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (for testing). */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns undefined if no preferences exist.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating defaults if none exist.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }
    return this.createDefaultPreferences(userId);
  }

  /**
   * Create default preferences for a user.
   */
  createDefaultPreferences(userId: string): UserPreferences {
    this.logger.info(`Creating default preferences for user: ${userId}`);

    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      throw new Error(`Preferences already exist for user: ${userId}`);
    }

    const now = new Date();
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(preferences);
    return preferences;
  }

  /**
   * Update email preferences for a user. Creates defaults first if none exist.
   */
  updateEmailPreferences(
    userId: string,
    input: UpdateEmailPreferencesInput,
  ): UserPreferences {
    this.logger.info(`Updating email preferences for user: ${userId}`);

    let preferences = this.preferencesRepository.findByUserId(userId);
    if (!preferences) {
      preferences = this.createDefaultPreferences(userId);
    }

    const updatedEmail = {
      ...preferences.email,
      ...(input.enabled !== undefined && { enabled: input.enabled }),
      ...(input.frequency !== undefined && { frequency: input.frequency }),
      ...(input.subscribedCategories !== undefined && {
        subscribedCategories: input.subscribedCategories,
      }),
    };

    const updated = this.preferencesRepository.update(preferences.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });

    return updated;
  }

  /**
   * Check whether a notification should be delivered via email for a given
   * recipient identifier (email address or user ID).
   *
   * Returns true if:
   * - No preferences record exists (opt-out model: deliver by default)
   * - Email is enabled AND the notification type is in subscribedCategories
   *
   * The NotificationService should call this before dispatching.
   */
  shouldSendEmail(
    userId: string,
    notificationType: NotificationType,
  ): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);

    // No preferences = deliver by default (opt-out model)
    if (!preferences) {
      return true;
    }

    if (!preferences.email.enabled) {
      return false;
    }

    return preferences.email.subscribedCategories.includes(notificationType);
  }

  /**
   * Delete preferences for a user (e.g., when user is deleted).
   */
  deletePreferences(userId: string): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);
    if (!preferences) {
      return false;
    }
    return this.preferencesRepository.delete(preferences.id);
  }
}

