private dispatchNotification(payload: NotificationPayload): void {
  // Check user preferences before dispatching
  if (this.preferencesService && payload.channel === 'email') {
    if (
      !this.preferencesService.shouldSendEmail(
        payload.recipient,
        payload.notificationType,
      )
    ) {
      this.logger.info(
        `Notification suppressed by preferences: ${payload.notificationType} to ${payload.recipient}`,
      );
      return;
    }
  }

  const priority: NotificationPriority = payload.priority ?? 'normal';

  const notification: Notification = {
    id: generateNotificationId(),
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    notificationType: payload.notificationType,
    channel: payload.channel,
    priority,
    delivered: false,
    createdAt: new Date(),
  };
  this.notifications.push(notification);

  // Emit for adapters to pick up
  this.eventBus.emit({
    type: 'notification:send',
    payload: { ...payload, priority },
    timestamp: notification.createdAt,
  });

  this.logger.info(`Notification dispatched: ${notification.id} to ${payload.recipient}`);
}

