import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import { DEFAULT_EMAIL_PREFERENCES } from '../../src/models/user-preferences.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent } from '../../src/events/event-types.js';

describe('PreferencesService', () => {
  let db: Database;
  let repository: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    repository = new PreferencesRepository(db);
    service = new PreferencesService(repository);
    resetPreferencesIdCounter();
  });

  describe('createDefaultPreferences', () => {
    it('should create default preferences for a user', () => {
      const prefs = service.createDefaultPreferences('user-0001');

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('instant');
      expect(prefs.email.subscribedCategories).toEqual(
        DEFAULT_EMAIL_PREFERENCES.subscribedCategories,
      );
    });

    it('should throw if preferences already exist for user', () => {
      service.createDefaultPreferences('user-0001');

      expect(() => service.createDefaultPreferences('user-0001')).toThrow(
        'Preferences already exist for user: user-0001',
      );
    });

    it('should generate sequential IDs', () => {
      const p1 = service.createDefaultPreferences('user-0001');
      const p2 = service.createDefaultPreferences('user-0002');

      expect(p1.id).toBe('pref-0001');
      expect(p2.id).toBe('pref-0002');
    });
  });

  describe('getPreferences', () => {
    it('should return undefined for nonexistent user', () => {
      expect(service.getPreferences('user-0001')).toBeUndefined();
    });

    it('should return preferences for existing user', () => {
      service.createDefaultPreferences('user-0001');
      const prefs = service.getPreferences('user-0001');

      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-0001');
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should create defaults if none exist', () => {
      const prefs = service.getOrCreatePreferences('user-0001');

      expect(prefs.userId).toBe('user-0001');
      expect(prefs.email.enabled).toBe(true);
    });

    it('should return existing preferences without creating new ones', () => {
      service.createDefaultPreferences('user-0001');
      const prefs = service.getOrCreatePreferences('user-0001');

      expect(prefs.id).toBe('pref-0001');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should update enabled flag', () => {
      service.createDefaultPreferences('user-0001');
      const updated = service.updateEmailPreferences('user-0001', {
        enabled: false,
      });

      expect(updated.email.enabled).toBe(false);
      expect(updated.email.frequency).toBe('instant');
    });

    it('should update frequency', () => {
      service.createDefaultPreferences('user-0001');
      const updated = service.updateEmailPreferences('user-0001', {
        frequency: 'daily',
      });

      expect(updated.email.frequency).toBe('daily');
    });

    it('should update subscribed categories', () => {
      service.createDefaultPreferences('user-0001');
      const updated = service.updateEmailPreferences('user-0001', {
        subscribedCategories: ['order_confirmation'],
      });

      expect(updated.email.subscribedCategories).toEqual([
        'order_confirmation',
      ]);
    });

    it('should create defaults first if no preferences exist', () => {
      const updated = service.updateEmailPreferences('user-0001', {
        frequency: 'weekly',
      });

      expect(updated.userId).toBe('user-0001');
      expect(updated.email.frequency).toBe('weekly');
      expect(updated.email.enabled).toBe(true);
    });

    it('should not change fields that are not provided', () => {
      service.createDefaultPreferences('user-0001');
      service.updateEmailPreferences('user-0001', { enabled: false });
      const prefs = service.getPreferences('user-0001')!;

      expect(prefs.email.enabled).toBe(false);
      expect(prefs.email.frequency).toBe('instant');
      expect(prefs.email.subscribedCategories).toEqual(
        DEFAULT_EMAIL_PREFERENCES.subscribedCategories,
      );
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (opt-out model)', () => {
      expect(service.shouldSendEmail('user-0001', 'order_confirmation')).toBe(
        true,
      );
    });

    it('should return true when email is enabled and category is subscribed', () => {
      service.createDefaultPreferences('user-0001');

      expect(service.shouldSendEmail('user-0001', 'order_confirmation')).toBe(
        true,
      );
    });

    it('should return false when email is disabled', () => {
      service.createDefaultPreferences('user-0001');
      service.updateEmailPreferences('user-0001', { enabled: false });

      expect(service.shouldSendEmail('user-0001', 'order_confirmation')).toBe(
        false,
      );
    });

    it('should return false when category is not subscribed', () => {
      service.createDefaultPreferences('user-0001');
      service.updateEmailPreferences('user-0001', {
        subscribedCategories: ['order_confirmation'],
      });

      expect(service.shouldSendEmail('user-0001', 'order_status_update')).toBe(
        false,
      );
    });

    it('should return false when subscribed categories is empty', () => {
      service.createDefaultPreferences('user-0001');
      service.updateEmailPreferences('user-0001', {
        subscribedCategories: [],
      });

      expect(service.shouldSendEmail('user-0001', 'order_confirmation')).toBe(
        false,
      );
    });
  });

  describe('deletePreferences', () => {
    it('should delete existing preferences', () => {
      service.createDefaultPreferences('user-0001');
      const result = service.deletePreferences('user-0001');

      expect(result).toBe(true);
      expect(service.getPreferences('user-0001')).toBeUndefined();
    });

    it('should return false for nonexistent preferences', () => {
      expect(service.deletePreferences('user-0001')).toBe(false);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let emailAdapter: EmailAdapter;

  const orderCreatedEvent: OrderCreatedEvent = {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
      ],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  };

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    emailAdapter = new EmailAdapter(eventBus);
    notificationService.registerAdapter(emailAdapter);

    const repository = new PreferencesRepository(db);
    preferencesService = new PreferencesService(repository);
    notificationService.setPreferencesService(preferencesService);

    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  it('should deliver notification when no preferences exist', async () => {
    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should deliver notification when user has default preferences', async () => {
    preferencesService.createDefaultPreferences('alice@example.com');
    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(1);
  });

  it('should suppress notification when email is disabled', async () => {
    preferencesService.createDefaultPreferences('alice@example.com');
    preferencesService.updateEmailPreferences('alice@example.com', {
      enabled: false,
    });

    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(0);
    expect(emailAdapter.getSentEmails()).toHaveLength(0);
  });

  it('should suppress notification when category is unsubscribed', async () => {
    preferencesService.createDefaultPreferences('alice@example.com');
    preferencesService.updateEmailPreferences('alice@example.com', {
      subscribedCategories: ['user_welcome'],
    });

    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(0);
  });

  it('should deliver notification when category is subscribed', async () => {
    preferencesService.createDefaultPreferences('alice@example.com');
    preferencesService.updateEmailPreferences('alice@example.com', {
      subscribedCategories: ['order_confirmation'],
    });

    await eventBus.emit(orderCreatedEvent);

    expect(notificationService.getNotificationCount()).toBe(1);
  });
});
